+function drawPlanningTable(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Wood table with detailed map scroll, 30x24 px approx, enhanced wood grain and map texture
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Table top (brown wood with grain)
+  ctx.fillStyle = '#6b4c2b';
+  ctx.fillRect(0, 8, 30, 12);
+  ctx.strokeStyle = '#5a3f21';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 28; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 10);
+    ctx.lineTo(i + 2, 18);
+    ctx.stroke();
+  }
+  // Additional wood grain texture
+  ctx.strokeStyle = '#7a5030';
+  ctx.lineWidth = 0.5;
+  for (let i = 3; i < 27; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 9);
+    ctx.lineTo(i + 1, 19);
+    ctx.stroke();
+  }
+  // Table legs with shading and wood grain
+  ctx.fillStyle = '#5a3f21';
+  ctx.fillRect(2, 20, 4, 6);
+  ctx.fillRect(24, 20, 4, 6);
+  ctx.strokeStyle = '#4a2f10';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(2, 20, 4, 6);
+  ctx.strokeRect(24, 20, 4, 6);
+  ctx.strokeStyle = '#6b4c2b';
+  ctx.lineWidth = 0.5;
+  for (let i = 3; i < 6; i += 2) {
+    ctx.beginPath();
+    ctx.moveTo(2 + i, 20);
+    ctx.lineTo(2 + i - 1, 26);
+    ctx.stroke();
+    ctx.beginPath();
+    ctx.moveTo(24 + i, 20);
+    ctx.lineTo(24 + i - 1, 26);
+    ctx.stroke();
+  }
+  // Map scroll (light parchment with rolled edges and texture)
+  ctx.fillStyle = '#d9cba3';
+  ctx.beginPath();
+  ctx.moveTo(6, 10);
+  ctx.lineTo(24, 10);
+  ctx.quadraticCurveTo(26, 12, 24, 18);
+  ctx.lineTo(6, 18);
+  ctx.quadraticCurveTo(4, 16, 6, 10);
+  ctx.fill();
+  ctx.strokeStyle = '#b8a97a';
+  ctx.lineWidth = 1;
+  ctx.stroke();
+  // Map details (green lines with dots)
+  ctx.strokeStyle = '#3a6b35';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(8, 12);
+  ctx.lineTo(22, 14);
+  ctx.moveTo(10, 16);
+  ctx.lineTo(20, 18);
+  ctx.stroke();
+  // Dots on map with shadow
+  ctx.fillStyle = '#2a4b25';
+  ctx.beginPath();
+  ctx.arc(12, 13, 1.5, 0, Math.PI * 2);
+  ctx.arc(18, 16, 1.5, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.fillStyle = 'rgba(0,0,0,0.1)';
+  ctx.beginPath();
+  ctx.arc(13, 14, 1.5, 0, Math.PI * 2);
+  ctx.arc(19, 17, 1.5, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.restore();
+}
