+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Rack frame (dark wood with grain)
+  ctx.fillStyle = '#4a2f1a';
+  ctx.fillRect(2, 4, 24, 20);
+  ctx.strokeStyle = '#3a2510';
+  ctx.lineWidth = 1;
+  for (let i = 4; i < 26; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 5);
